proof:
constructor <;> intro h;
· intro c
  intro h'
  obtain ⟨k, hk⟩ := h
  use h' ≫ k
  simp [hk];
  -- By associativity of composition, we can rewrite the left-hand side as h' ≫ (k ≫ f).
  have h_assoc : (h' ≫ k) ≫ f = h' ≫ (k ≫ f) := by
    exact C.assoc _ _ _;
  exact h_assoc.trans ( by rw [ hk, C.comp_id ] );
· exact Exists.elim ( h Y ( C.id Y ) ) fun g hg => ⟨ g, hg ⟩

